// entries/page/SitePage.schema.tsx
import {Config, Field} from 'alinea'

export const SitePage = Config.document('Page', {
  contains: ['SitePage'],
  fields: {
    title: Field.text('Title', {required: true}),
    path: Field.path('Path', {required: true}),
    blocks: Field.list('Blocks', {
      schema: {
        TextBlock,
        ImageBlock,
        GalleryBlock
      }
    })
  }
})

// cms.tsx (root allows nested SitePage entries)
const pages = Config.root('Pages', {
  contains: ['SitePage', 'BlogPage'],
  children: {
    index: Config.page({type: SitePage, fields: {title: 'Home', path: ''}}),
    products: Config.page({
      type: SitePage,
      fields: {title: 'Products', path: 'products'},
      children: {
        enterprise: Config.page({
          type: SitePage,
          fields: {title: 'Enterprise', path: 'enterprise'}
        })
      }
    })
  }
})

// app/[[...slug]]/page.tsx
import {Entry} from 'alinea/core/Entry'
import {notFound} from 'next/navigation'
import {cms} from '@/cms'
import {LandingPageView} from '@/entries/landing/LandingPage'
import {BlogPageView} from '@/entries/blog/BlogPage'
import {BlogPostPageView} from '@/entries/blog/BlogPostPage'

interface RouteProps {
  params: Promise<{slug?: Array<string>}>
}

export async function generateStaticParams() {
  const urls = await cms.find({
    root: cms.workspaces.main.pages,
    select: Entry.url
  })

  return urls.map(url => ({slug: url === '/' ? [] : url.slice(1).split('/')}))
}

export default async function CatchAllPage({params}: RouteProps) {
  const {slug = []} = await params
  const url = slug.length > 0 ? `/${slug.join('/')}` : '/'
  const page = await cms.get({url})

  if (!page) notFound()

  if (page._type === 'BlogPage') {
    const posts = await cms.find({
      parentId: page._id,
      select: {
        id: Entry.id,
        title: Entry.title,
        url: Entry.url
      }
    })
    return <BlogPageView page={page} posts={posts} />
  }

  if (page._type === 'PostPage') {
    return <BlogPostPageView post={page} />
  }

  return <LandingPageView page={page} />
}
